package com.treeeducation.ioas.audit; import com.treeeducation.ioas.common.*;import io.swagger.v3.oas.annotations.*;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.data.domain.*;import org.springframework.web.bind.annotation.*; /** Audit log query API. */ @RestController @RequestMapping("/api/v1/audit/logs") @Tag(name="Audit",description="上传、删除、恢复、创建线索等操作日志") public class AuditLogController{private final AuditLogRepository repo; public AuditLogController(AuditLogRepository repo){this.repo=repo;} @GetMapping @Operation(summary="审计日志列表") public ApiResponse<PageResponse<AuditLogDtos.Response>> list(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.ok(PageResponse.of(repo.findAllByOrderByCreatedAtDesc(PageRequest.of(page,size)).map(AuditLogDtos::of)));}}
